WHERE TE_NOME = 'NEXI') WHERE CO_AUTH_GROUP_ID = (SELECT CO_ID FROM ${database.defaultSchemaName}.AUTH_GROUP
WHERE TE_NOME = 'PAGOPA_AMMINISTRATIVA');
