  SET TE_NOME = 'pagopa-dadgroup-smo-kpi-prn-amministrativa', TE_DESCRIZIONE = 'Gruppo degli amministratori Pagopa', FL_LIVELLO_VISIBILITA = 2, TE_OBJECTID = '01e88978-9b30-4abe-b2a9-b76aa5b4594c'
  WHERE TE_NOME = 'NEXI';
