INSERT INTO ${database.defaultSchemaName}.AUTH_GROUP_AUTH_FUNC (CO_AUTH_FUNCTION_ID, CO_AUTH_GROUP_ID)
SELECT af.co_id, (SELECT co_id FROM ${database.defaultSchemaName}.auth_group WHERE te_nome = 'PAGOPA_AMMINISTRATIVA')
FROM ${database.defaultSchemaName}.auth_function af
WHERE af.te_nome IN ('MODULE_INQUIRY', 'MODULE_MANAGEMENT', 'JOB_MANAGEMENT', 'STATION_INQUIRY',
'USER_MANAGEMENT', 'INSTANCE_INQUIRY', 'BASIC_FUNCTIONS', 'INSTITUTION_INQUIRY',
'USER_INQUIRY', 'KPI_CONFIGURATION_MANAGEMENT', 'KPI_CONFIGURATION_INQUIRY',
'TAXONOMY_INQUIRY', 'PARTNER_INQUIRY', 'SHUTDOWN_MANAGEMENT', 'SHUTDOWN_INQUIRY',
'INSTANCE_MANAGEMENT', 'JOB_INQUIRY'
);
